generated_oml:
// Sensing components
instance TemperatureSensorInside : DTDFVocab:SensingComponent [
    base:desc "Temperature sensor positioned inside the Styrofoam insulated incubator, recording temperature continuously for real-time monitoring."
    DTDFVocab:producedData TemperatureTelemetry
]

instance HumiditySensorInside : DTDFVocab:SensingComponent [
    base:desc "Humidity sensor inside the incubator, continuously measuring relative humidity for process control."
    DTDFVocab:producedData HumidityTelemetry
]

// Data transmitted from Raspberry Pi over MQTT/RabbitMQ
instance TemperatureTelemetry : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TemperatureSensorInside
]

instance HumidityTelemetry : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HumiditySensorInside
]

// Aggregated time‑series data
instance TemperatureTimeSeries : DTDFVocab:Data [
    base:desc "Continuous temperature time‑series aggregated from telemetry for use in model calibration and monitoring."
    DTDFVocab:fromData TemperatureTelemetry
    DTDFVocab:inputTo CalibrationAlgorithmEnabler, DifferentialEquationSolverEnabler
]

instance HumidityTimeSeries : DTDFVocab:Data [
    base:desc "Continuous humidity time‑series aggregated from telemetry for use in model calibration and monitoring."
    DTDFVocab:fromData HumidityTelemetry
    DTDFVocab:inputTo CalibrationAlgorithmEnabler, DifferentialEquationSolverEnabler
]

// Models
instance DynamicIncubatorThermalModel : DTDFVocab:Model [
    base:desc "Dynamic thermodynamic model expressed as differential equations representing heat‑bed element, fan convection, and insulation."
    DTDFVocab:inputTo DifferentialEquationSolverEnabler, CalibrationAlgorithmEnabler
]

instance EnvironmentalModel : DTDFVocab:Model [
    base:desc "Static model of laboratory environment capturing ambient temperature and humidity."
    DTDFVocab:inputTo CalibrationAlgorithmEnabler
]

// Enablers
instance CalibrationAlgorithmEnabler : DTDFVocab:Enabler [
    base:desc "Python calibration algorithm module employing scipy.optimize to estimate model parameters from sensor data."
    DTDFVocab:enables ModelCalibrationService, FaultDetectionService, StateEstimationService, PredictiveSimulationService
]

instance DifferentialEquationSolverEnabler : DTDFVocab:Enabler [
    base:desc "Python solver executing differential equations for predictive simulation of temperature dynamics."
    DTDFVocab:enables PredictiveSimulationService
]

instance OptimizationAlgorithmEnabler : DTDFVocab:Enabler [
    base:desc "Python optimization module using scipy.optimize to find optimal heat‑bed setpoints for energy efficiency."
    DTDFVocab:enables OptimizationService
]

instance MessagingBrokerEnabler : DTDFVocab:Enabler [
    base:desc "RabbitMQ messaging broker exchanging telemetry and command messages between Raspberry Pi and cloud simulation layer."
    DTDFVocab:enables RealTimeMonitoringService, PredictiveSimulationService
]

instance VisualizationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Matplotlib-based visualization engine mapping model outputs to dashboards."
    DTDFVocab:enables VisualizationService
]

instance CloudSimulationEnabler : DTDFVocab:Enabler [
    base:desc "Cloud simulation layer that receives calibrated models and runs predictive simulations."
    DTDFVocab:enables PredictiveSimulationService
]

instance DataCollectionEnabler : DTDFVocab:Enabler [
    base:desc "MQTT data collector on Raspberry Pi ingesting sensor streams for downstream processing."
    DTDFVocab:enables RealTimeMonitoringService
]

// Services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Real-time monitoring service validating predictions against sensor data to ensure safety and optimal operation; triggers alerts or actions when thresholds are exceeded."
    DTDFVocab:provides SafetyComplianceInsight, OptimalOperationInsight, AlertHumanOperatorAction
]

instance PredictiveSimulationService : DTDFVocab:Service [
    base:desc "Predictive simulation service generating future temperature and humidity trajectories using calibrated models."
    DTDFVocab:provides PredictedTemperatureInsight, PredictedHumidityInsight
]

instance FaultDetectionService : DTDFVocab:Service [
    base:desc "Fault detection service applying fault detector algorithms to identify anomalies."
    DTDFVocab:provides FaultDetectionInsight
]

instance StateEstimationService : DTDFVocab:Service [
    base:desc "State estimation service computing current system state using state estimator."
    DTDFVocab:provides StateEstimateInsight
]

instance ModelCalibrationService : DTDFVocab:Service [
    base:desc "Model calibration service updating dynamic models based on continuous sensor data."
    DTDFVocab:provides ModelCalibrationInsight
]

instance SupervisoryControlService : DTDFVocab:Service [
    base:desc "Supervisory control service executing commanded heat‑bed temperature or fan speed setpoints based on optimization and state estimation."
    DTDFVocab:provides ExecuteControlCommandAction
]

instance OptimizationService : DTDFVocab:Service [
    base:desc "Optimization service generating energy‑efficient control recommendations using optimization algorithms."
    DTDFVocab:provides OptimizationRecommendationAction
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Visualization service mapping predictive and real-time data onto operator dashboards using Matplotlib."
    DTDFVocab:provides VisualizationDashboardInsight
]

// Insights
instance SafetyComplianceInsight : DTDFVocab:Insight [
    base:desc "Insight indicating whether incubator temperature and humidity remain within safety envelope."
]

instance OptimalOperationInsight : DTDFVocab:Insight [
    base:desc "Insight indicating whether system operates within optimal efficiency envelope."
]

instance PredictedTemperatureInsight : DTDFVocab:Insight [
    base:desc "Insight providing forecasted temperature profile for upcoming time horizon."
]

instance PredictedHumidityInsight : DTDFVocab:Insight [
    base:desc "Insight providing forecasted humidity trajectory."
]

instance FaultDetectionInsight : DTDFVocab:Insight [
    base:desc "Insight highlighting detected fault conditions and severity."
]

instance StateEstimateInsight : DTDFVocab:Insight [
    base:desc "Insight presenting estimated current system state of temperature distribution and heat input."
]

instance ModelCalibrationInsight : DTDFVocab:Insight [
    base:desc "Insight indicating updated model parameters and calibration residuals."
]

instance VisualizationDashboardInsight : DTDFVocab:Insight [
    base:desc "Insight representing current state visualized on operator dashboard."
]

// Actions
instance AlertHumanOperatorAction : DTDFVocab:Action [
    base:desc "Action to alert human operators with recommendation for intervention (manual override)."
    DTDFVocab:IsAutomatic false
]

instance ExecuteControlCommandAction : DTDFVocab:Action [
    base:desc "Action automatically driving heat‑bed temperature or fan speed setpoints via MQTT commands."
    DTDFVocab:IsAutomatic true
]

instance OptimizationRecommendationAction : DTDFVocab:Action [
    base:desc "Action recommending optimal control setpoints to operator."
    DTDFVocab:IsAutomatic false
]

// Physical components
instance StylingInsulation : DTDFVocab:Component [
    base:desc "Styrofoam insulating material surrounding the incubator enclosure."
]

instance HeatBedElement : DTDFVocab:ActingComponent [
    base:desc "Actuating component that delivers controlled heating to maintain desired temperature."
]

instance FanActuator : DTDFVocab:ActingComponent [
    base:desc "Actuating component providing air circulation within the incubator."
]

// Environment
instance LabEnvironment : DTDFVocab:Environment [
    base:contains StylingInsulation, HeatBedElement, FanActuator, TemperatureSensorInside, HumiditySensorInside
]
